subprograms.code:
procedure Get
          (  Source  : in String;
             Pointer : in out Integer;
             Value   : out Roman;
             First   : in Roman := Roman'First;
             Last    : in Roman := Roman'Last;
             ToFirst : in Boolean := False;
             ToLast  : in Boolean := False
          )

function Image
         (  Value     : in Roman;
            LowerCase : in Boolean := False
         )  return String

procedure Put
          (  Destination : in out String;
             Pointer     : in out Integer;
             Value       : in Roman;
             LowerCase   : in Boolean := False;
             Field       : in Natural := 0;
             Justify     : in Alignment := Left;
             Fill        : in Character := ' '
          )

function Value
         (  Source  : in String;
            First   : in Roman := Roman'First;
            Last    : in Roman := Roman'Last;
            ToFirst : in Boolean := False;
            ToLast  : in Boolean := False
         )  return Roman
